import { Component } from '@angular/core';
import { RouterLink } from '@angular/router';

@Component({
  selector: 'app-home',
  standalone: true,
  imports: [RouterLink],
  templateUrl: './home.component.html',
  styleUrl: './home.component.css'
})
export class HomeComponent {}
<div class="p-4 bg-light rounded border">
  <h2>Cadastro de Livros</h2>
  <p class="mb-3">Projeto CRUD de Livro, Autor e Assunto + Relatório PDF (via VIEW).</p>

  <div class="d-flex gap-2 flex-wrap">
    <a class="btn btn-primary" routerLink="/livros">Livros</a>
    <a class="btn btn-outline-primary" routerLink="/autores">Autores</a>
    <a class="btn btn-outline-primary" routerLink="/assuntos">Assuntos</a>
    <a class="btn btn-dark" routerLink="/relatorio">Relatório</a>
  </div>
</div>
